    phpArrayFunctions() +
    phpClassobjFunctions() +
    phpCtypeFunctions() +
    phpDatetimeFunctions() +
    phpFilesystemFunctions() +
    phpFunchandFunctions() +
    phpJsonFunctions() +
    phpMathFunctions() +
    phpPcreFunctions() +
    phpStringsFunctions() +
    phpUrlFunctions() +
    phpVarFunctions()
